77	func enableExecuteBeadWorktreeConfig(projectRoot string) error {
78		if out, err := internalgit.Command(context.Background(), projectRoot, "config", "extensions.worktreeConfig", "true").CombinedOutput(); err != nil {
79			return fmt.Errorf("enable extensions.worktreeConfig for execute-bead worktree: %s: %w",
80				strings.TrimSpace(string(out)), err)
81		}
82		return nil
83	}
