111	func seedExecuteBeadWorktreeConfig(projectRoot, worktreeGitDir string) error {
112		dst := filepath.Join(worktreeGitDir, "config.worktree")
113		if info, err := os.Stat(dst); err == nil && info.Size() > 0 {
114			return nil
115		}
116	
117		commonDirOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--git-common-dir").Output()
118		if err != nil {
119			return fmt.Errorf("locating git common dir for execute-bead: %w", err)
120		}
121		commonDir := strings.TrimSpace(string(commonDirOut))
122		if !filepath.IsAbs(commonDir) {
123			commonDir = filepath.Clean(filepath.Join(projectRoot, commonDir))
124		}
125		src := filepath.Join(commonDir, "config")
126		data, err := os.ReadFile(src)
127		if err != nil {
128			return fmt.Errorf("read shared git config for execute-bead seed: %w", err)
129		}
130		if err := os.WriteFile(dst, data, 0o644); err != nil {
131			return fmt.Errorf("write worktree config seed: %w", err)
132		}
133		return nil
134	}
