136	func ensureExecuteBeadPrivateConfig(path string) error {
137		if info, err := os.Stat(path); err == nil && !info.IsDir() {
138			return nil
139		}
140		if err := os.MkdirAll(filepath.Dir(path), 0o755); err != nil {
141			return fmt.Errorf("create private git config dir: %w", err)
142		}
143		if err := os.WriteFile(path, []byte{}, 0o644); err != nil {
144			return fmt.Errorf("create private git config: %w", err)
145		}
146		return nil
147	}
