149	func renderExecuteBeadGitWrapper(realGit, privateCfg string) string {
150		return fmt.Sprintf(`#!/usr/bin/env bash
151	set -euo pipefail
152	
153	real_git=%q
154	private_cfg=%q
155	
156	args=("$@")
157	sub_idx=-1
158	i=0
159	while (( i < ${#args[@]} )); do
160	  case "${args[$i]}" in
161	    -C|--git-dir|--work-tree|--namespace|--exec-path|--super-prefix|--config-env|-c)
162	      ((i+=2))
163	      continue
164	      ;;
165	    --)
166	      ((i++))
167	      break
168	      ;;
169	    -*)
170	      ((i++))
171	      continue
172	      ;;
173	    *)
174	      sub_idx=$i
175	      break
176	      ;;
177	  esac
178	done
179	
180	if (( sub_idx >= 0 )) && [[ "${args[$sub_idx]}" == "config" ]]; then
181	  prefix=("${args[@]:0:sub_idx}")
182	  suffix=("${args[@]:sub_idx+1}")
183	
184	  repo_scope_idx=-1
185	  explicit_scope=0
186	  dangerous_key=0
187	  for i in "${!suffix[@]}"; do
188	    case "${suffix[$i]}" in
189	      core.bare|core.worktree)
190	        dangerous_key=1
191	        ;;
192	      --local|--worktree)
193	        repo_scope_idx=$i
194	        explicit_scope=1
195	        ;;
196	      --global|--system|--file|--blob)
197	        explicit_scope=1
198	        ;;
199	    esac
200	  done

