107		if err := os.MkdirAll(filepath.Dir(wtPath), 0o755); err != nil {
108			return nil, fmt.Errorf("creating execute-bead worktree parent dir: %w", err)
109		}
110		if err := gitOps.WorktreeAdd(req.ProjectRoot, wtPath, req.BaseRev); err != nil {
111			_ = os.RemoveAll(wtPath)
112			return nil, fmt.Errorf("creating isolated worktree: %w", err)
113		}
114		return &AttemptWorkspace{
115			Backend:     AttemptBackendWorktree,
116			ProjectRoot: req.ProjectRoot,
117			WorkDir:     wtPath,
118			BeadID:      req.BeadID,
119			AttemptID:   req.AttemptID,
120			BaseRev:     req.BaseRev,
121			gitOps:      gitOps,
122		}, nil
