256			return nil, fmt.Errorf("resolving ddx executable for docker backend: %w", err)
257		}
258		promptPath, err := containerPath(req.Workspace.WorkDir, req.Runtime.PromptFile)
259		if err != nil {
260			return nil, err
261		}
262	
263		containerName := dockerContainerName(req.Workspace)
264		args := dockerRunArgs(cfg, req.Workspace, exe, image, dockerToolMounts())
265		runArgs := []string{
266			"ddx", "run",
267			"--project", "/work",
268			"--prompt", promptPath,
269			"--output", "json-result",
270			"--permissions", firstNonEmpty(req.Runtime.PermissionsOverride, req.Config.Permissions()),
271		}
272		if h := strings.TrimSpace(req.Config.Harness()); h != "" {
273			runArgs = append(runArgs, "--harness", h)
274		}
275		if p := strings.TrimSpace(req.Config.Provider()); p != "" {
276			runArgs = append(runArgs, "--provider", p)
277		}
278		if m := strings.TrimSpace(req.Config.Model()); m != "" {
279			runArgs = append(runArgs, "--model", m)
280		}
281		if p := strings.TrimSpace(req.Config.Profile()); p != "" {
282			runArgs = append(runArgs, "--profile", p)
283		}
284		if e := strings.TrimSpace(req.Config.Effort()); e != "" {
285			runArgs = append(runArgs, "--effort", e)
286		}
287		if min := req.Config.MinPower(); min > 0 {
288			runArgs = append(runArgs, "--min-power", strconv.Itoa(min))
