3	import (
4		"os"
5		"path/filepath"
6	)
7	
8	// skillLinkDirs lists the project-local skill directories that an execute-bead
9	// worktree must clean before the agent runs. In the post-FEAT-015 model these
10	// contain real files; pre-migration worktrees may still have symlinks whose
11	// targets no longer exist (the old global plugin tree is gone). Broken
12	// symlinks are removed silently so the harness does not emit "failed to stat"
13	// errors on startup.
14	var skillLinkDirs = []string{
15		filepath.Join(".agents", "skills"),
16		filepath.Join(".claude", "skills"),
17	}
18	
19	// materializeWorktreeSkills cleans up broken symlinks in the project-local
20	// skill directories inside an execute-bead worktree. Real files and valid
21	// symlinks are left untouched. Broken symlinks (pre-migration remnants) are
22	// removed so the harness does not log stat errors.
23	func materializeWorktreeSkills(wtPath string) error {
24		for _, rel := range skillLinkDirs {
25			dir := filepath.Join(wtPath, rel)
26			if err := repairSkillLinkDir(dir); err != nil {
27				return err
28			}
29		}
30		return nil
31	}
32	
33	// repairSkillLinkDir walks a single skill directory and removes broken
34	// symlinks. It is a no-op when dir does not exist.
35	func repairSkillLinkDir(dir string) error {
36		entries, err := os.ReadDir(dir)
37		if err != nil {
38			if os.IsNotExist(err) {
39				return nil
40			}
41			return err
42		}
43		for _, e := range entries {
44			entryPath := filepath.Join(dir, e.Name())
45			info, err := os.Lstat(entryPath)
46			if err != nil {
47				continue
48			}
49			if info.Mode()&os.ModeSymlink == 0 {
50				continue
51			}
52			// Resolved successfully? Leave it alone.
53			if _, err := os.Stat(entryPath); err == nil {
54				continue
55			}
56			// Broken symlink — remove so the harness stops logging stat errors.
57			_ = os.Remove(entryPath)
58		}
59		return nil
60	}
