150	func (b LocalCloneAttemptBackend) Prepare(ctx context.Context, req AttemptBackendPrepareRequest) (*AttemptWorkspace, error) {
151		clonePath := executeBeadClonePath(req.ProjectRoot, req.BeadID, req.AttemptID)
152		if err := os.MkdirAll(filepath.Dir(clonePath), 0o755); err != nil {
153			return nil, fmt.Errorf("creating execute-bead clone parent dir: %w", err)
154		}
155	
156		cloneArgs := localCloneArgs(b.CloneMode, req.ProjectRoot, clonePath)
157		if out, err := internalgit.Command(ctx, req.ProjectRoot, cloneArgs...).CombinedOutput(); err != nil {
158			if shouldRetryCloneWithoutHardlinks(b.CloneMode, out) {
159				_ = os.RemoveAll(clonePath)
160				cloneArgs = localCloneArgs("no-hardlinks", req.ProjectRoot, clonePath)
161				out, err = internalgit.Command(ctx, req.ProjectRoot, cloneArgs...).CombinedOutput()
162			}
163			if err == nil {
164				goto checkout
165			}
166			_ = os.RemoveAll(clonePath)
167			return nil, fmt.Errorf("creating isolated clone: %s: %w", strings.TrimSpace(string(out)), err)
168		}
169	checkout:
170		if out, err := internalgit.Command(ctx, clonePath, "checkout", "--detach", req.BaseRev).CombinedOutput(); err != nil {
171			_ = os.RemoveAll(clonePath)
172			return nil, fmt.Errorf("checking out isolated clone base: %s: %w", strings.TrimSpace(string(out)), err)
173		}
174		seedAttemptCloneUserConfig(ctx, req.ProjectRoot, clonePath)
175		configureAttemptCloneTransientExcludes(clonePath)
176	
177		return &AttemptWorkspace{
178			Backend:     AttemptBackendLocalClone,
179			ProjectRoot: req.ProjectRoot,
180			WorkDir:     clonePath,
181			BeadID:      req.BeadID,
182			AttemptID:   req.AttemptID,
183			BaseRev:     req.BaseRev,
184		}, nil
185	}
