238	func (b DockerCloneAttemptBackend) Run(ctx context.Context, req AttemptBackendRunRequest) (*Result, error) {
239		cfg := b.Docker
240		image := ""
241		if cfg != nil {
242			image = strings.TrimSpace(cfg.Image)
243		}
244		if image == "" {
245			return nil, fmt.Errorf("docker-clone attempt backend requires executions.docker.image")
246		}
247		if req.Workspace == nil || req.Workspace.WorkDir == "" {
248			return nil, fmt.Errorf("docker-clone attempt backend missing workspace")
249		}
250		image, err := resolveDockerAttemptImage(ctx, cfg, req.ProjectRoot, image)
251		if err != nil {
252			return nil, err
253		}
254		exe, err := os.Executable()
255		if err != nil {
256			return nil, fmt.Errorf("resolving ddx executable for docker backend: %w", err)
257		}
258		promptPath, err := containerPath(req.Workspace.WorkDir, req.Runtime.PromptFile)
259		if err != nil {
260			return nil, err
261		}
262	
263		containerName := dockerContainerName(req.Workspace)
264		args := dockerRunArgs(cfg, req.Workspace, exe, image, dockerToolMounts())
265		runArgs := []string{
266			"ddx", "run",
267			"--project", "/work",
268			"--prompt", promptPath,
269			"--output", "json-result",
270			"--permissions", firstNonEmpty(req.Runtime.PermissionsOverride, req.Config.Permissions()),
271		}
272		if h := strings.TrimSpace(req.Config.Harness()); h != "" {
273			runArgs = append(runArgs, "--harness", h)
274		}
275		if p := strings.TrimSpace(req.Config.Provider()); p != "" {
276			runArgs = append(runArgs, "--provider", p)
277		}
278		if m := strings.TrimSpace(req.Config.Model()); m != "" {
279			runArgs = append(runArgs, "--model", m)
280		}
281		if p := strings.TrimSpace(req.Config.Profile()); p != "" {
282			runArgs = append(runArgs, "--profile", p)
283		}
284		if e := strings.TrimSpace(req.Config.Effort()); e != "" {
285			runArgs = append(runArgs, "--effort", e)
286		}
287		if min := req.Config.MinPower(); min > 0 {
288			runArgs = append(runArgs, "--min-power", strconv.Itoa(min))
289		}
290		if max := req.Config.MaxPower(); max > 0 {
291			runArgs = append(runArgs, "--max-power", strconv.Itoa(max))
292		}
293		if timeout := req.Config.Timeout(); timeout > 0 {
294			runArgs = append(runArgs, "--timeout", timeout.String())
295		}
296		args = append(args, runArgs...)
297	
298		cmd := dockerAttemptCommand(ctx, args...)
299		cmd.Dir = req.Workspace.ProjectRoot
300		var stdout, stderr bytes.Buffer
301		cmd.Stdout = &stdout
302		cmd.Stderr = &stderr
303		defer func() {
304			_ = dockerRemoveContainer(context.Background(), containerName)
305		}()
306		err = cmd.Run()
307	
308		result, parseErr := parseDockerRunResult(stdout.Bytes())
309		if parseErr == nil {
310			if strings.TrimSpace(stderr.String()) != "" && result.Stderr == "" {
311				result.Stderr = strings.TrimSpace(stderr.String())
312			}
313			return result, nil
314		}
315		if err != nil {
316			return nil, fmt.Errorf("docker-clone attempt failed: %s: %w", strings.TrimSpace(stderr.String()), err)
317		}
318		return nil, parseErr
319	}
