390			_ = releaseExclusiveLock(ws.inTreeLockFile)
391			_ = ws.inTreeLockFile.Close()
392		}
393		if ws.BeadID != "" {
394			lockPath := executeBeadInTreeLockPath(ws.ProjectRoot, ws.BeadID)
395			_ = os.Remove(lockPath)
396		}
397		return nil
398	}
