507	func configureAttemptCloneTransientExcludes(clonePath string) {
508		out, err := internalgit.Command(context.Background(), clonePath, "rev-parse", "--git-path", "info/exclude").Output()
509		if err != nil {
510			return
511		}
512		excludePath := strings.TrimSpace(string(out))
513		if excludePath == "" {
514			return
515		}
516		if !filepath.IsAbs(excludePath) {
517			excludePath = filepath.Join(clonePath, excludePath)
518		}
519		if err := os.MkdirAll(filepath.Dir(excludePath), 0o755); err != nil {
520			return
521		}
522		raw, _ := os.ReadFile(excludePath)
523		text := string(raw)
524		var additions []string
525		for _, pattern := range []string{"/.gocache/", "/.tmp/"} {
526			if !excludeTextHasPattern(text, pattern) {
527				additions = append(additions, pattern)
528			}
529		}
530		if len(additions) == 0 {
531			return
532		}
533		if len(text) > 0 && !strings.HasSuffix(text, "\n") {
534			text += "\n"
535		}
536		text += strings.Join(additions, "\n") + "\n"
537		_ = os.WriteFile(excludePath, []byte(text), 0o644)
538	}
539	
540	func excludeTextHasPattern(text, pattern string) bool {
541		for _, line := range strings.Split(text, "\n") {
542			if strings.TrimSpace(line) == pattern {
543				return true
544			}
545		}
546		return false
547	}
