557	func publishCloneResult(ctx context.Context, ws *AttemptWorkspace, res *ExecuteBeadResult) error {
558		if ws == nil || res == nil || ws.WorkDir == "" || ws.ProjectRoot == "" {
559			return nil
560		}
561		resultRev := strings.TrimSpace(res.ResultRev)
562		if resultRev == "" || resultRev == res.BaseRev {
563			return nil
564		}
565		srcRef := attemptBackendResultRef("source", ws.BeadID, ws.AttemptID)
566		dstRef := attemptBackendResultRef("result", ws.BeadID, ws.AttemptID)
567		if out, err := internalgit.Command(ctx, ws.WorkDir, "update-ref", srcRef, resultRev).CombinedOutput(); err != nil {
568			return fmt.Errorf("pinning clone result ref: %s: %w", strings.TrimSpace(string(out)), err)
569		}
570		refspec := "+" + srcRef + ":" + dstRef
571		if out, err := internalgit.Command(ctx, ws.ProjectRoot, "fetch", "--no-tags", ws.WorkDir, refspec).CombinedOutput(); err != nil {
572			return fmt.Errorf("importing clone result: %s: %w", strings.TrimSpace(string(out)), err)
573		}
574		return nil
575	}
