918	func dockerCredentialEnv() []string {
919		prefixes := []string{
920			"ANTHROPIC_", "CODEX_", "FIZEAU_", "GEMINI_", "GOOGLE_",
921			"OPENAI_", "OPENROUTER_",
922		}
923		var env []string
924		for _, kv := range os.Environ() {
925			name, _, ok := strings.Cut(kv, "=")
926			if !ok {
927				continue
928			}
929			for _, prefix := range prefixes {
930				if strings.HasPrefix(name, prefix) {
931					env = append(env, name)
932					break
933				}
934			}
935		}
936		return env
937	}
