950	func parseDockerRunResult(raw []byte) (*Result, error) {
951		trimmed := bytes.TrimSpace(raw)
952		if len(trimmed) == 0 {
953			return nil, fmt.Errorf("docker-clone produced no JSON result")
954		}
955		start := bytes.IndexByte(trimmed, '{')
956		if start < 0 {
957			return nil, fmt.Errorf("docker-clone output did not contain a JSON result")
958		}
959		var result Result
960		if err := json.Unmarshal(trimmed[start:], &result); err != nil {
961			return nil, fmt.Errorf("decoding docker-clone JSON result: %w", err)
962		}
963		return &result, nil
964	}
