966	func sanitizeDockerName(s string) string {
967		var b strings.Builder
968		for _, r := range s {
969			switch {
970			case r >= 'a' && r <= 'z', r >= 'A' && r <= 'Z', r >= '0' && r <= '9', r == '-', r == '_', r == '.':
971				b.WriteRune(r)
972			default:
973				b.WriteByte('-')
974			}
975		}
976		out := strings.Trim(b.String(), "-_.")
977		if out == "" {
978			return "attempt"
979		}
980		if len(out) > 80 {
981			return out[:80]
982		}
983		return out
984	}
