101	func normalizeExecutionWorktreeRoot(path, relativeBase string) string {
102		path = strings.TrimSpace(path)
103		if path == "" {
104			return ""
105		}
106		if path == "~" {
107			if home, err := os.UserHomeDir(); err == nil && home != "" {
108				path = home
109			}
110		} else if strings.HasPrefix(path, "~/") {
111			if home, err := os.UserHomeDir(); err == nil && home != "" {
112				path = filepath.Join(home, strings.TrimPrefix(path, "~/"))
113			}
114		}
115		if !filepath.IsAbs(path) && strings.TrimSpace(relativeBase) != "" {
116			path = filepath.Join(relativeBase, path)
117		}
118		return filepath.Clean(path)
119	}
